                linear-gradient(135deg, rgba(15, 23, 42, 0.97), rgba(30, 41, 59, 0.95)),
                url('https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=1600&h=800&fit=crop&q=90') center/cover;
            color: white;
            padding: 4rem 2rem 3rem;
            text-align: center;
            border-bottom: 4px solid #f59e0b;
        }
        .hero-content {
            max-width: 900px;
            margin: 0 auto;
        }
        .urgency-badge {
            display: inline-block;
            background: linear-gradient(135deg, #f59e0b, #d97706);
            color: #0f172a;
            padding: 0.6rem 1.5rem;
            border-radius: 50px;
            font-size: 0.85rem;
            font-weight: 800;
            text-transform: uppercase;
            letter-spacing: 1px;
            margin-bottom: 1.5rem;
            box-shadow: 0 4px 15px rgba(245, 158, 11, 0.5);
        }
        .hero h1 {
            font-size: 3.8rem;
            font-weight: 900;
            margin-bottom: 1rem;
            line-height: 1.1;
            letter-spacing: -1px;
        }
        .hero h1 .highlight {
            color: #f59e0b;
            text-shadow: 0 0 30px rgba(245, 158, 11, 0.5);
        }
        .hero .subtitle {
            font-size: 1.3rem;
            margin-bottom: 2rem;
            font-weight: 500;
            color: #cbd5e1;
        }
        .price-container {
            margin-bottom: 2rem;
        }
        .price-badge {
            display: inline-block;
            background: linear-gradient(135deg, #f59e0b, #d97706);
            color: #0f172a;
            padding: 1rem 2.5rem;
            border-radius: 12px;
            font-size: 3.2rem;
            font-weight: 900;
            box-shadow: 0 10px 40px rgba(245, 158, 11, 0.4);
        }
        .cta-main {
            display: inline-block;
            background: linear-gradient(135deg, #f59e0b, #d97706);
            color: #0f172a;
            padding: 1.3rem 3.5rem;
            font-size: 1.2rem;
            font-weight: 900;
            border-radius: 8px;
            text-decoration: none;
            text-transform: uppercase;
            letter-spacing: 1px;
            box-shadow: 0 6px 25px rgba(245, 158, 11, 0.5);
            transition: all 0.3s;
            border: 2px solid transparent;
        }
        .cta-main:hover {
            background: linear-gradient(135deg, #d97706, #b45309);
            transform: translateY(-2px);
            box-shadow: 0 8px 35px rgba(245, 158, 11, 0.6);
            border-color: #fbbf24;
        }

.timeline {
            padding: 7rem 2rem;
            background: #f9fafb;
        }
        .container {
            max-width: 1400px;
            margin: 0 auto;
        }
        .section-title {
            text-align: center;
            font-size: 2.8rem;
            font-weight: 900;
            margin-bottom: 1rem;
            color: #0f172a;
            letter-spacing: -0.5px;
        }
        .section-subtitle {
            text-align: center;
            font-size: 1.3rem;
            color: #64748b;
            margin-bottom: 4rem;
            font-weight: 500;
        }
        .timeline-grid {
            display: grid;
            grid-template-columns: repeat(5, 1fr);
            gap: 1.5rem;
            max-width: 1200px;
            margin: 0 auto;
            position: relative;
        }
        .timeline-grid::before {
            content: '';
            position: absolute;
            top: 3rem;
            left: 10%;
            right: 10%;
            height: 4px;
            background: linear-gradient(90deg, #f59e0b, #d97706);
            z-index: 0;
        }
        .timeline-item {
            text-align: center;
            padding: 2rem 1rem;
            background: white;
            border-radius: 15px;
            border: 3px solid #0f172a;
            position: relative;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
            transition: all 0.3s;
            z-index: 1;
        }
        .timeline-item:hover {
            transform: translateY(-8px);
            box-shadow: 0 15px 40px rgba(245, 158, 11, 0.3);
            border-color: #f59e0b;
        }
        .timeline-time {
            font-size: 2.5rem;
            font-weight: 900;
            color: #0f172a;
            margin-bottom: 0.5rem;
        }
        .timeline-action {
            font-size: 0.95rem;
            font-weight: 700;
            color: #475569;
            line-height: 1.4;
        }

.checkout-overlay {
            display: none;
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.85);
            z-index: 10000;
            align-items: center;
            justify-content: center;
            backdrop-filter: blur(8px);
        }
        .checkout-overlay.active {
            display: flex;
        }
        .checkout-modal {
            background: #ffffff;
            border-radius: 12px;
            max-width: 480px;
            width: 90%;
            padding: 0;
            position: relative;
            box-shadow: 0 20px 60px rgba(0,0,0,0.3);
            animation: slideIn 0.4s ease-out;
            overflow: hidden;
        }
        @keyframes slideIn {
            from { transform: translateY(-50px); opacity: 0; }
            to { transform: translateY(0); opacity: 1; }
        }
        .checkout-close {
            position: absolute;
            top: 1rem;
            right: 1rem;
            background: white;
            border: 1px solid #e5e7eb;
            font-size: 1.5rem;
            cursor: pointer;
            color: #64748b;
            transition: all 0.2s;
            width: 32px;
            height: 32px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 6px;
            z-index: 10;
        }
        .checkout-close:hover {
            background: #f1f5f9;
            color: #0f172a;
            border-color: #cbd5e1;
        }
        .checkout-header {
            background: #f8fafc;
            padding: 2rem;
            border-bottom: 1px solid #e5e7eb;
        }
        .checkout-merchant {
            display: flex;
            align-items: center;
            gap: 0.75rem;
            margin-bottom: 1rem;
        }
        .merchant-logo {
            width: 48px;
            height: 48px;
            background: linear-gradient(135deg, #0f172a, #1e293b);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #f59e0b;
            font-weight: 900;
            font-size: 1.5rem;
        }
        .merchant-info h3 {
            font-size: 1.1rem;
            font-weight: 700;
            color: #0f172a;
            margin: 0;
        }
        .merchant-info p {
            font-size: 0.85rem;
            color: #64748b;
            margin: 0;
        }
        .checkout-header p {
            color: #475569;
            font-size: 0.9rem;
            margin: 0;
        }
        .checkout-body {
            padding: 1.5rem;
        }
        .checkout-amount {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 1rem 0;
            border-bottom: 1px solid #e5e7eb;
            margin-bottom: 1.5rem;
        }
        .checkout-amount-label {
            font-size: 0.95rem;
            color: #64748b;
            font-weight: 600;
        }
        .checkout-amount-value {
            font-size: 1.8rem;
            font-weight: 800;
            color: #0f172a;
        }
        .checkout-includes {
            font-size: 0.8rem;
            color: #059669;
            margin-top: 0.5rem;
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }
        .payment-methods {
            margin-bottom: 2rem;
        }
        .payment-tabs {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 0.5rem;
            margin-bottom: 1.5rem;
        }
        .payment-tab {
            padding: 0.9rem 0.5rem;
            border: 2px solid #e5e7eb;
            border-radius: 6px;
            text-align: center;
            cursor: pointer;
            transition: all 0.2s;
            background: white;
            font-weight: 600;
            font-size: 0.85rem;
            color: #475569;
        }
        .payment-tab:hover {
            border-color: #cbd5e1;
            background: #f8fafc;
        }
        .payment-tab.active {
            border-color: #f59e0b;
            background: #fffbeb;
            color: #0f172a;
        }
        .payment-content {
            display: none;
        }
        .payment-content.active {
            display: block;
        }
        .bank-select label {
            display: block;
            font-size: 0.85rem;
            font-weight: 600;
            margin-bottom: 0.75rem;
            color: #475569;
        }
        .bank-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 0.5rem;
        }
        .bank-option {
            border: 2px solid #e5e7eb;
            border-radius: 8px;
            padding: 1rem 0.5rem;
            text-align: center;
            cursor: pointer;
            transition: all 0.2s;
            background: white;
            min-height: 70px;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
        }
        .bank-option:hover {
            border-color: #cbd5e1;
            background: #f8fafc;
        }
        .bank-option.selected {
            border-color: #f59e0b;
            background: #fffbeb;
            box-shadow: 0 0 0 1px #f59e0b;
        }
        .bank-logo {
            width: 100%;
            height: 32px;
            display: flex;
            align-items: center;
            justify-content: center;
            margin-bottom: 0.25rem;
        }
        .bank-option span {
            display: block;
            font-size: 0.7rem;
            font-weight: 600;
            color: #64748b;
        }
        .card-form {
            display: flex;
            flex-direction: column;
            gap: 1rem;
        }
        .form-group {
            display: flex;
            flex-direction: column;
        }
        .form-group label {
            font-size: 0.85rem;
            font-weight: 700;
            margin-bottom: 0.5rem;
            color: #1a1a1a;
        }
        .form-group input {
            padding: 0.9rem;
            border: 2px solid #e5e7eb;
            border-radius: 8px;
            font-size: 1rem;
            transition: all 0.3s;
        }
        .form-group input:focus {
            outline: none;
            border-color: #f59e0b;
            background: #fef3c7;
        }
        .form-row {
            display: grid;
            grid-template-columns: 2fr 1fr;
            gap: 1rem;
        }
        .card-icons {
            display: flex;
            gap: 0.5rem;
            margin-top: 0.5rem;
        }
        .card-icon {
            width: 40px;
            height: 25px;
            border: 1px solid #e5e7eb;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 0.7rem;
            font-weight: 700;
            background: white;
        }
        .paypal-button {
            background: #0070ba;
            color: white;
            padding: 1.5rem;
            border-radius: 8px;
            text-align: center;
            font-weight: 700;
            font-size: 1.1rem;
            cursor: pointer;
            transition: all 0.3s;
        }
        .paypal-button:hover {
            background: #005ea6;
        }
        .checkout-submit {
            width: 100%;
            background: #0f172a;
            color: white;
            padding: 1rem;
            border: none;
            border-radius: 6px;
            font-size: 1rem;
            font-weight: 700;
            cursor: pointer;
            transition: all 0.2s;
            margin-top: 1rem;
        }
        .checkout-submit:hover:not(:disabled) {
            background: #1e293b;
        }
        .checkout-submit:disabled {
            background: #cbd5e1;
            color: #94a3b8;
            cursor: not-allowed;
        }
        .checkout-footer {
            padding: 1rem 1.5rem;
            background: #f8fafc;
            border-top: 1px solid #e5e7eb;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 1rem;
            flex-wrap: wrap;
        }
        .secure-badge {
            display: flex;
            align-items: center;
            gap: 0.4rem;
            font-size: 0.75rem;
            color: #64748b;
        }
        .secure-badge svg {
            width: 14px;
            height: 14px;
        }
        .payment-logos {
            display: flex;
            gap: 0.5rem;
            align-items: center;
        }
        .payment-logo {
            height: 18px;
            opacity: 0.6;
        }

